import{c as a,Q as n,j as r,m as t}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"Agent Harness Engineering — 論文與資源總覽","description":"","frontmatter":{"title":"Agent Harness Engineering — 論文與資源總覽","type":"documentation"},"headers":[],"relativePath":"research/agent-harness/SURVEY.md","filePath":"research/agent-harness/SURVEY.md","lastUpdated":1779894392000}'),i={name:"research/agent-harness/SURVEY.md"};function o(l,e,s,g,h,c){return n(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="agent-harness-engineering-—-論文與資源總覽" tabindex="-1">Agent Harness Engineering — 論文與資源總覽 <a class="header-anchor" href="#agent-harness-engineering-—-論文與資源總覽" aria-label="Permalink to &quot;Agent Harness Engineering — 論文與資源總覽&quot;">​</a></h1><blockquote><p>建立時間：2026-05-01<br> 覆蓋範圍：arXiv 論文 · 工程博客 · Benchmark 報告<br> 更新策略：每季補充新論文；Ratchet 新增洞見至 KNOWLEDGE-MAP.md</p></blockquote><hr><h2 id="priority-a-—-核心論文-必讀" tabindex="-1">Priority A — 核心論文（必讀） <a class="header-anchor" href="#priority-a-—-核心論文-必讀" aria-label="Permalink to &quot;Priority A — 核心論文（必讀）&quot;">​</a></h2><h3 id="_1-agentic-harness-engineering-observability-driven-automatic-evolution" tabindex="-1">1. Agentic Harness Engineering: Observability-Driven Automatic Evolution <a class="header-anchor" href="#_1-agentic-harness-engineering-observability-driven-automatic-evolution" aria-label="Permalink to &quot;1. Agentic Harness Engineering: Observability-Driven Automatic Evolution&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.25850" target="_blank" rel="noreferrer">2604.25850</a></li><li><strong>發表</strong>: 2026-04</li><li><strong>摘要</strong>: 提出 AHE 框架，透過三個可觀測性柱子（元件 / 經驗 / 決策）自動進化 agent harnesses。核心洞見：harness 改進應由工具、中介軟體、長期記憶主導，而非系統提示詞。</li><li><strong>關鍵成果</strong>: <ul><li>Terminal-Bench 2: pass@1 69.7% → 77.0%（10 次迭代）</li><li>SWE-bench-verified: 用 12% 更少 token 達最佳成績</li><li>跨模型族遷移收益：+5.1 到 +10.1 pp</li></ul></li><li><strong>與 FRAMEWORK.md 的連結</strong>: 直接驗證「harness &gt; model」命題；Ratchet 自動化演進的學術支撐</li></ul><hr><h3 id="_2-building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering" tabindex="-1">2. Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering <a class="header-anchor" href="#_2-building-ai-coding-agents-for-the-terminal-scaffolding-harness-context-engineering" aria-label="Permalink to &quot;2. Building AI Coding Agents for the Terminal: Scaffolding, Harness, Context Engineering&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.05344" target="_blank" rel="noreferrer">2603.05344</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>摘要</strong>: 首篇系統區分「Scaffolding（組裝期）」vs「Harness（執行期）」概念的論文。介紹 OPENDEV（Rust 終端機代理），強調適應性 context 壓縮、雙代理架構。</li><li><strong>Scaffolding 定義</strong>: 系統提示、工具定義、subagent 註冊</li><li><strong>Harness 定義</strong>: 工具分派、context 管理、安全執行、session 持久化</li><li><strong>架構創新</strong>: 工作負載專門化模型路由、懶惰工具發現、自動化記憶系統</li></ul><hr><h3 id="_3-inside-the-scaffold-a-source-code-taxonomy-of-coding-agent-architectures" tabindex="-1">3. Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures <a class="header-anchor" href="#_3-inside-the-scaffold-a-source-code-taxonomy-of-coding-agent-architectures" aria-label="Permalink to &quot;3. Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.03515" target="_blank" rel="noreferrer">2604.03515</a></li><li><strong>發表</strong>: 2026-04</li><li><strong>摘要</strong>: 首次對 13 個開源 coding agents 進行源碼層級架構分析，提出跨 12 維度、3 層組織的統一分類學。</li><li><strong>5 個通用控制原語</strong>: <ol><li>ReAct（推理-行動交錯）</li><li>Generate-test-repair</li><li>Plan-execute</li><li>Multi-attempt retry</li><li>Tree search</li></ol></li><li><strong>關鍵發現</strong>: 11/13 agents 混合多個原語，而非單一模式</li></ul><hr><h2 id="priority-b-—-重要論文" tabindex="-1">Priority B — 重要論文 <a class="header-anchor" href="#priority-b-—-重要論文" aria-label="Permalink to &quot;Priority B — 重要論文&quot;">​</a></h2><h3 id="_4-natural-language-agent-harnesses-nlah" tabindex="-1">4. Natural-Language Agent Harnesses (NLAH) <a class="header-anchor" href="#_4-natural-language-agent-harnesses-nlah" aria-label="Permalink to &quot;4. Natural-Language Agent Harnesses (NLAH)&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.25723" target="_blank" rel="noreferrer">2603.25723</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>摘要</strong>: 提出用自然語言表達 harness 行為，引入 Natural-Language Agent Harnesses (NLAHs) 與 Intelligent Harness Runtime (IHR)。解決 harness「深埋在控制器代碼中」的可移植性問題。</li><li><strong>核心價值</strong>: 使 harness 設計可跨系統遷移、可對比、可科學研究</li></ul><hr><h3 id="_5-meta-harness-end-to-end-optimization-of-model-harnesses" tabindex="-1">5. Meta-Harness: End-to-End Optimization of Model Harnesses <a class="header-anchor" href="#_5-meta-harness-end-to-end-optimization-of-model-harnesses" aria-label="Permalink to &quot;5. Meta-Harness: End-to-End Optimization of Model Harnesses&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.28052" target="_blank" rel="noreferrer">2603.28052</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>摘要</strong>: 外層迴圈系統，透過訪問原始代碼、分數和所有先前執行軌跡，用 agent 搜尋 harness 代碼空間。類似 Neural Architecture Search，但針對 harness 層。</li></ul><hr><h3 id="_6-react-synergizing-reasoning-and-acting-in-language-models" tabindex="-1">6. ReAct: Synergizing Reasoning and Acting in Language Models <a class="header-anchor" href="#_6-react-synergizing-reasoning-and-acting-in-language-models" aria-label="Permalink to &quot;6. ReAct: Synergizing Reasoning and Acting in Language Models&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">2210.03629</a></li><li><strong>發表</strong>: 2022-10（ICLR 2023）</li><li><strong>摘要</strong>: LLM agent 的基礎論文。定義推理跡象（reasoning traces）與行動（actions）的交錯模式。推理幫助歸納、追蹤、更新行動計畫；行動與外部環境互動。</li><li><strong>成果</strong>: HotpotQA 超越 CoT；ALFWorld +34% 絕對成功率</li></ul><hr><h3 id="_7-agent-harness-for-large-language-model-agents-a-survey" tabindex="-1">7. Agent Harness for Large Language Model Agents: A Survey <a class="header-anchor" href="#_7-agent-harness-for-large-language-model-agents-a-survey" aria-label="Permalink to &quot;7. Agent Harness for Large Language Model Agents: A Survey&quot;">​</a></h3><ul><li><strong>來源</strong>: Preprints.org, 2026-03</li><li><strong>摘要</strong>: 直指核心：「隨著 agent 任務變長變複雜，執行可靠性越來越不是模型能力問題，而是包裹在它周圍的『基礎設施層』——agent 執行 harness」。</li></ul><hr><h3 id="_8-memory-for-autonomous-llm-agents-mechanisms-evaluation-and-emerging-frontiers" tabindex="-1">8. Memory for Autonomous LLM Agents: Mechanisms, Evaluation, and Emerging Frontiers <a class="header-anchor" href="#_8-memory-for-autonomous-llm-agents-mechanisms-evaluation-and-emerging-frontiers" aria-label="Permalink to &quot;8. Memory for Autonomous LLM Agents: Mechanisms, Evaluation, and Emerging Frontiers&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.07670" target="_blank" rel="noreferrer">2603.07670</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>摘要</strong>: long-running agents 的記憶設計調查。Pattern B（主流）：working memory 在 context window，長期記錄在外部向量/結構化存儲，每步檢索相關記錄。</li><li><strong>核心挑戰</strong>: 檢索品質是瓶頸</li><li><strong>相關論文</strong>: A-Mem [2502.12110]、MemGPT [2310.08560]</li></ul><hr><h3 id="_9-agentic-artificial-intelligence-architectures-taxonomies-and-evaluation" tabindex="-1">9. Agentic Artificial Intelligence: Architectures, Taxonomies, and Evaluation <a class="header-anchor" href="#_9-agentic-artificial-intelligence-architectures-taxonomies-and-evaluation" aria-label="Permalink to &quot;9. Agentic Artificial Intelligence: Architectures, Taxonomies, and Evaluation&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2601.12560" target="_blank" rel="noreferrer">2601.12560</a></li><li><strong>發表</strong>: 2026-01</li><li><strong>摘要</strong>: 新一代 LLM agents 作為結合記憶、工具使用、環境反饋的認知控制器。涵蓋 CAMEL、AutoGen、MetaGPT、LangGraph、Swarm 等框架；互動模式有 chain、star、mesh。</li></ul><hr><h2 id="priority-c-—-工具與方法論論文" tabindex="-1">Priority C — 工具與方法論論文 <a class="header-anchor" href="#priority-c-—-工具與方法論論文" aria-label="Permalink to &quot;Priority C — 工具與方法論論文&quot;">​</a></h2><h3 id="_10-learning-to-rewrite-tool-descriptions-for-reliable-llm-agent-tool-use" tabindex="-1">10. Learning to Rewrite Tool Descriptions for Reliable LLM-Agent Tool Use <a class="header-anchor" href="#_10-learning-to-rewrite-tool-descriptions-for-reliable-llm-agent-tool-use" aria-label="Permalink to &quot;10. Learning to Rewrite Tool Descriptions for Reliable LLM-Agent Tool Use&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2602.20426" target="_blank" rel="noreferrer">2602.20426</a></li><li><strong>發表</strong>: 2026-02</li><li><strong>摘要</strong>: 工具描述的措辭會顯著影響 agent 成功率。提出自動化重寫工具 schema 和描述以提升可靠性。</li></ul><hr><h3 id="_11-act-while-thinking-pattern-aware-speculative-tool-execution" tabindex="-1">11. Act While Thinking: Pattern-Aware Speculative Tool Execution <a class="header-anchor" href="#_11-act-while-thinking-pattern-aware-speculative-tool-execution" aria-label="Permalink to &quot;11. Act While Thinking: Pattern-Aware Speculative Tool Execution&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.18897" target="_blank" rel="noreferrer">2603.18897</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>摘要</strong>: 在 agent 完成思考前並行執行工具，減少延遲。</li></ul><hr><h3 id="_12-design-patterns-for-securing-llm-agents-against-prompt-injections" tabindex="-1">12. Design Patterns for Securing LLM Agents against Prompt Injections <a class="header-anchor" href="#_12-design-patterns-for-securing-llm-agents-against-prompt-injections" aria-label="Permalink to &quot;12. Design Patterns for Securing LLM Agents against Prompt Injections&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2506.08837" target="_blank" rel="noreferrer">2506.08837</a></li><li><strong>發表</strong>: 2025-06</li><li><strong>摘要</strong>: LLM agent 安全防禦模式，針對提示詞注入等攻擊。</li></ul><hr><h3 id="_13-architecting-resilient-llm-agents-secure-plan-and-execute-architectures" tabindex="-1">13. Architecting Resilient LLM Agents: Secure Plan-and-Execute Architectures <a class="header-anchor" href="#_13-architecting-resilient-llm-agents-secure-plan-and-execute-architectures" aria-label="Permalink to &quot;13. Architecting Resilient LLM Agents: Secure Plan-and-Execute Architectures&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2509.08646" target="_blank" rel="noreferrer">2509.08646</a></li><li><strong>發表</strong>: 2025-09</li></ul><hr><h2 id="工程博客資源" tabindex="-1">工程博客資源 <a class="header-anchor" href="#工程博客資源" aria-label="Permalink to &quot;工程博客資源&quot;">​</a></h2><h3 id="_14-lilian-weng-—-llm-powered-autonomous-agents" tabindex="-1">14. Lilian Weng — LLM Powered Autonomous Agents <a class="header-anchor" href="#_14-lilian-weng-—-llm-powered-autonomous-agents" aria-label="Permalink to &quot;14. Lilian Weng — LLM Powered Autonomous Agents&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://lilianweng.github.io/posts/2023-06-23-agent/" target="_blank" rel="noreferrer">https://lilianweng.github.io/posts/2023-06-23-agent/</a></li><li><strong>發表</strong>: 2023-06-23</li><li><strong>定位</strong>: 業界標準入門文章；Planning-Memory-Tools 三層框架的經典定義</li><li><strong>核心框架</strong>: <ul><li>Planning: Task Decomposition（CoT, ToT）+ Self-Reflection</li><li>Memory: Sensory / Short-term（context）/ Long-term（向量存儲）</li><li>Tools: 外部 API 超越訓練數據限制</li></ul></li><li><strong>特點</strong>: ReAct 框架的清晰圖解；MIPS 檢索算法（FAISS、ANNOY）說明</li></ul><hr><h3 id="_15-eugene-yan-—-patterns-for-building-llm-based-systems-products" tabindex="-1">15. Eugene Yan — Patterns for Building LLM-based Systems &amp; Products <a class="header-anchor" href="#_15-eugene-yan-—-patterns-for-building-llm-based-systems-products" aria-label="Permalink to &quot;15. Eugene Yan — Patterns for Building LLM-based Systems &amp; Products&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://eugeneyan.com/writing/llm-patterns/" target="_blank" rel="noreferrer">https://eugeneyan.com/writing/llm-patterns/</a></li><li><strong>定位</strong>: 生產級 LLM 系統的 7 大設計模式</li><li><strong>7 大 Patterns</strong>: Evals、RAG、Fine-tuning、Caching、Guardrails、Defensive UX、Collect User Feedback</li><li><strong>Agent Harness 相關洞見</strong>: <ul><li>「專化模型組隊」勝過單一通才</li><li>Hybrid 方法（傳統 + embedding）優於單一策略</li><li>Guardrails + Evals 是生產環境必需品</li></ul></li></ul><hr><h3 id="_16-adnan-masood-—-agent-harness-engineering-the-rise-of-the-ai-control-plane" tabindex="-1">16. Adnan Masood — Agent Harness Engineering: The Rise of the AI Control Plane <a class="header-anchor" href="#_16-adnan-masood-—-agent-harness-engineering-the-rise-of-the-ai-control-plane" aria-label="Permalink to &quot;16. Adnan Masood — Agent Harness Engineering: The Rise of the AI Control Plane&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d</a></li><li><strong>發表</strong>: 2026-04</li><li><strong>核心</strong>: 5 層 Control Plane 架構視角 <ol><li>Context Management</li><li>Tool/Function Calling</li><li>Execution Loop（Observe-Think-Act）</li><li>State &amp; Memory</li><li>Safety &amp; Observability</li></ol></li><li><strong>關鍵統計</strong>: 企業 AI 失敗 65% 源自 harness 層缺陷，而非模型限制</li><li><strong>獨特觀點</strong>: 正確 cache 管理可將 token 成本降低十倍</li></ul><hr><h3 id="_17-daily-dose-of-ds-—-the-anatomy-of-an-agent-harness" tabindex="-1">17. Daily Dose of DS — The Anatomy of an Agent Harness <a class="header-anchor" href="#_17-daily-dose-of-ds-—-the-anatomy-of-an-agent-harness" aria-label="Permalink to &quot;17. Daily Dose of DS — The Anatomy of an Agent Harness&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness" target="_blank" rel="noreferrer">https://blog.dailydoseofds.com/p/the-anatomy-of-an-agent-harness</a></li><li><strong>定位</strong>: 最完整的 harness 組件分解（11 個生產級組件）</li><li><strong>11 個核心組件</strong>: <ol><li>Orchestration Loop（Thought-Action-Observation）</li><li>Tools（schema + 執行 + 驗證 + 結果格式化）</li><li>Memory（短期 + 長期）</li><li>Context Management（壓縮、masking、即時檢索、子 agent）</li><li>Prompt Construction（系統提示 → 工具定義 → 記憶 → 對話）</li><li>Output Parsing（結構化物件，避免自由文本）</li><li>State Management（類型化字典 + 邊界檢查點）</li><li>Error Handling（暫時性/LLM 可恢復/用戶可修正/意外性）</li><li>Guardrails &amp; Safety（輸入/輸出/工具層三層）</li><li>Verification Loops（規則型/視覺型/LLM-as-judge）</li><li>Subagent Orchestration（專門 agent + 完整交接）</li></ol></li><li><strong>核心論點</strong>: Verification 能使品質提升 2-3 倍；LangChain 只改 harness 就從外賽區升至第 5 名</li></ul><hr><h3 id="_18-langchain-—-agent-engineering-a-new-discipline" tabindex="-1">18. LangChain — Agent Engineering: A New Discipline <a class="header-anchor" href="#_18-langchain-—-agent-engineering-a-new-discipline" aria-label="Permalink to &quot;18. LangChain — Agent Engineering: A New Discipline&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://blog.langchain.com/agent-engineering-a-new-discipline/" target="_blank" rel="noreferrer">https://blog.langchain.com/agent-engineering-a-new-discipline/</a></li><li><strong>定位</strong>: Agent Engineering 作為工程學科的宣言</li><li><strong>核心定義</strong>: 「將非確定性 LLM 系統迭代精煉為可靠生產體驗的過程」</li><li><strong>工程循環</strong>: Build → Test → Ship → Observe → Refine → Repeat</li><li><strong>跨職能要求</strong>: Product thinking + Engineering + Data Science</li><li><strong>關鍵轉變</strong>: 放棄「發布前完美」，改為快速發行 + 生產學習</li></ul><hr><h2 id="benchmark-資源" tabindex="-1">Benchmark 資源 <a class="header-anchor" href="#benchmark-資源" aria-label="Permalink to &quot;Benchmark 資源&quot;">​</a></h2><h3 id="_19-swe-bench-swe-bench-verified-swe-bench-pro" tabindex="-1">19. SWE-bench / SWE-bench Verified / SWE-bench Pro <a class="header-anchor" href="#_19-swe-bench-swe-bench-verified-swe-bench-pro" aria-label="Permalink to &quot;19. SWE-bench / SWE-bench Verified / SWE-bench Pro&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://www.swebench.com/" target="_blank" rel="noreferrer">https://www.swebench.com/</a></li><li><strong>規模</strong>: 2,294 issues；Verified 版 500 個（人工 3 倍驗證）</li><li><strong>評估 Harness 設計</strong>: 最小化 bash-tool-only，Docker 容器化隔離</li><li><strong>2026 最新成績（SWE-bench Pro）</strong>: Claude Opus 4.7 64.3%、GPT-5.4 57.7%</li></ul><h3 id="_20-terminal-bench-2-0" tabindex="-1">20. Terminal-Bench 2.0 <a class="header-anchor" href="#_20-terminal-bench-2-0" aria-label="Permalink to &quot;20. Terminal-Bench 2.0&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://www.tbench.ai/leaderboard/terminal-bench/2.0" target="_blank" rel="noreferrer">https://www.tbench.ai/leaderboard/terminal-bench/2.0</a></li><li><strong>特點</strong>: 終端實務工作（編譯/訓練/部署）；39 個模型排行</li><li><strong>Harness 洞見</strong>: 同一 Opus 4.6，不同 harness → 13 pp 差距（66.9% → 79.8%）</li></ul><h3 id="_21-agentbench-iclr-2024" tabindex="-1">21. AgentBench（ICLR 2024） <a class="header-anchor" href="#_21-agentbench-iclr-2024" aria-label="Permalink to &quot;21. AgentBench（ICLR 2024）&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2308.03688" target="_blank" rel="noreferrer">2308.03688</a></li><li><strong>特點</strong>: 8 種環境多輪推理評估；29 個模型測試</li></ul><h3 id="_22-webarena" tabindex="-1">22. WebArena <a class="header-anchor" href="#_22-webarena" aria-label="Permalink to &quot;22. WebArena&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://webarena.dev/" target="_blank" rel="noreferrer">https://webarena.dev/</a></li><li><strong>特點</strong>: 812 個網頁自主操作任務；2 年間成績 14% → 60%</li></ul><hr><h2 id="推薦閱讀順序" tabindex="-1">推薦閱讀順序 <a class="header-anchor" href="#推薦閱讀順序" aria-label="Permalink to &quot;推薦閱讀順序&quot;">​</a></h2><h3 id="week-1-—-建立基礎理論" tabindex="-1">Week 1 — 建立基礎理論 <a class="header-anchor" href="#week-1-—-建立基礎理論" aria-label="Permalink to &quot;Week 1 — 建立基礎理論&quot;">​</a></h3><ol><li>ReAct (#6) — 推理-行動交錯基礎</li><li>Lilian Weng (#14) — Planning-Memory-Tools 三層框架</li><li>AHE (#1) — 最新 SOTA 與自動演進</li></ol><h3 id="week-2-—-深入架構設計" tabindex="-1">Week 2 — 深入架構設計 <a class="header-anchor" href="#week-2-—-深入架構設計" aria-label="Permalink to &quot;Week 2 — 深入架構設計&quot;">​</a></h3><ol start="4"><li>Scaffolding vs Harness 區分 (#2) — 術語定義</li><li>Inside the Scaffold Taxonomy (#3) — 12 維度、5 原語</li><li>Daily Dose of DS Anatomy (#17) — 11 組件生產級分解</li><li>Adnan Masood Control Plane (#16) — 5 層視角</li></ol><h3 id="week-3-—-實踐與評估" tabindex="-1">Week 3 — 實踐與評估 <a class="header-anchor" href="#week-3-—-實踐與評估" aria-label="Permalink to &quot;Week 3 — 實踐與評估&quot;">​</a></h3><ol start="8"><li>Natural-Language Harnesses (#4) — 可移植性</li><li>Memory for Agents (#8) — long-running 策略</li><li>Eugene Yan Patterns (#15) — 生產模式</li><li>Agent Engineering Discipline (#18) — 工程學科</li></ol><h3 id="reference-—-按需查閱" tabindex="-1">Reference — 按需查閱 <a class="header-anchor" href="#reference-—-按需查閱" aria-label="Permalink to &quot;Reference — 按需查閱&quot;">​</a></h3><ul><li>SWE-bench / Terminal-Bench（效能基準）</li><li>Security papers (#12, #13)（安全防禦）</li><li>Speculative execution (#11)（效能優化）</li></ul><hr><h2 id="_2026-05-最新-harness-論文" tabindex="-1">2026-05 最新 Harness 論文 <a class="header-anchor" href="#_2026-05-最新-harness-論文" aria-label="Permalink to &quot;2026-05 最新 Harness 論文&quot;">​</a></h2><h3 id="_23-continual-harness" tabindex="-1">23. Continual Harness <a class="header-anchor" href="#_23-continual-harness" aria-label="Permalink to &quot;23. Continual Harness&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.09998" target="_blank" rel="noreferrer">2605.09998</a></li><li><strong>發表</strong>: 2026-05-11</li><li><strong>摘要</strong>: Online adaptation for self-improving foundation agents; runtime harness modification without retraining.</li></ul><h3 id="_24-harness-engineering-as-categorical-architecture" tabindex="-1">24. Harness Engineering as Categorical Architecture <a class="header-anchor" href="#_24-harness-engineering-as-categorical-architecture" aria-label="Permalink to &quot;24. Harness Engineering as Categorical Architecture&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.12239" target="_blank" rel="noreferrer">2605.12239</a></li><li><strong>發表</strong>: 2026-05-12</li><li><strong>摘要</strong>: Category theory framework for harness composition; functorial mappings between tool schemas.</li></ul><h3 id="_25-meta-harness-finn-et-al" tabindex="-1">25. Meta-Harness (Finn et al.) <a class="header-anchor" href="#_25-meta-harness-finn-et-al" aria-label="Permalink to &quot;25. Meta-Harness (Finn et al.)&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.28052" target="_blank" rel="noreferrer">2603.28052</a></li><li><strong>發表</strong>: 2026-05-12</li><li><strong>摘要</strong>: End-to-end optimization of model harnesses; Chelsea Finn / Stanford group; joint optimization of harness+model (supersedes #5 entry dated 2026-03).</li></ul><h3 id="_26-ai-harness-engineering-runtime-substrate" tabindex="-1">26. AI Harness Engineering: Runtime Substrate <a class="header-anchor" href="#_26-ai-harness-engineering-runtime-substrate" aria-label="Permalink to &quot;26. AI Harness Engineering: Runtime Substrate&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.13357" target="_blank" rel="noreferrer">2605.13357</a></li><li><strong>發表</strong>: 2026-05-13</li><li><strong>摘要</strong>: Runtime substrate for foundation-model software agents; Zhong &amp; Zhu; execution layer taxonomy.</li></ul><h3 id="_27-effective-harness-engineering-for-algorithm-discovery" tabindex="-1">27. Effective Harness Engineering for Algorithm Discovery <a class="header-anchor" href="#_27-effective-harness-engineering-for-algorithm-discovery" aria-label="Permalink to &quot;27. Effective Harness Engineering for Algorithm Discovery&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.15221" target="_blank" rel="noreferrer">2605.15221</a></li><li><strong>發表</strong>: 2026-05-15</li><li><strong>摘要</strong>: Vesper framework for coding agent harness design; empirical on algorithm discovery benchmarks.</li></ul><h3 id="_28-code-as-agent-harness" tabindex="-1">28. Code as Agent Harness <a class="header-anchor" href="#_28-code-as-agent-harness" aria-label="Permalink to &quot;28. Code as Agent Harness&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.18747" target="_blank" rel="noreferrer">2605.18747</a></li><li><strong>發表</strong>: 2026-05-18</li><li><strong>摘要</strong>: Using code structure itself as the harness; Ning et al.; tool schema compilation from code.</li></ul><h3 id="_29-adapting-the-interface-not-the-model" tabindex="-1">29. Adapting the Interface, Not the Model <a class="header-anchor" href="#_29-adapting-the-interface-not-the-model" aria-label="Permalink to &quot;29. Adapting the Interface, Not the Model&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.22166" target="_blank" rel="noreferrer">2605.22166</a></li><li><strong>發表</strong>: 2026-05-21</li><li><strong>摘要</strong>: Runtime harness adaptation for deterministic LLM agents; Xu et al.; interface-level vs weight-level adaptation.</li></ul><h3 id="_30-cheating-agents-benchmark-manipulation" tabindex="-1">30. Cheating Agents: Benchmark Manipulation <a class="header-anchor" href="#_30-cheating-agents-benchmark-manipulation" aria-label="Permalink to &quot;30. Cheating Agents: Benchmark Manipulation&quot;">​</a></h3><ul><li><strong>發表</strong>: 2026-05-23 (DebugML)</li><li><strong>摘要</strong>: Widespread benchmark manipulation in LLM agent evaluations; implications for harness benchmark validity.</li></ul><h3 id="_31-coordination-architectural-layer" tabindex="-1">31. Coordination Architectural Layer <a class="header-anchor" href="#_31-coordination-architectural-layer" aria-label="Permalink to &quot;31. Coordination Architectural Layer&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.03310" target="_blank" rel="noreferrer">2605.03310</a></li><li><strong>發表</strong>: 2026-05-05</li><li><strong>摘要</strong>: Multi-agent coordination as a distinct architectural layer.</li></ul><h3 id="_32-heavyskill" tabindex="-1">32. HeavySkill <a class="header-anchor" href="#_32-heavyskill" aria-label="Permalink to &quot;32. HeavySkill&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2605.02396" target="_blank" rel="noreferrer">2605.02396</a></li><li><strong>發表</strong>: 2026-05-04</li><li><strong>摘要</strong>: Heavy thinking inner skill; extended reasoning within harness skill invocations.</li></ul>',102)])])}const f=a(i,[["render",o]]);export{d as __pageData,f as default};
